CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;


DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260418153720_InitialCreate') THEN
    CREATE TABLE "CollectionThemes" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Name" character varying(100) NOT NULL,
        "Description" text NOT NULL,
        "IsHoliday" boolean NOT NULL,
        "ImagePath" text NOT NULL,
        CONSTRAINT "PK_CollectionThemes" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260418153720_InitialCreate') THEN
    CREATE TABLE "Users" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "FullName" text NOT NULL,
        "Login" text NOT NULL,
        "Email" text NOT NULL,
        "Phone" text NOT NULL,
        "PasswordHash" text NOT NULL,
        "Role" integer NOT NULL,
        "Balance" numeric(10,2) NOT NULL,
        "IsBlocked" boolean NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        "UpdatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_Users" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260418153720_InitialCreate') THEN
    CREATE TABLE "ServiceItems" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "CollectionThemeId" integer NOT NULL,
        "Name" character varying(140) NOT NULL,
        "Description" text NOT NULL,
        "Price" numeric(10,2) NOT NULL,
        "DurationMinutes" integer NOT NULL,
        "ImagePath" text NOT NULL,
        "IsHoliday" boolean NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        "LastModifiedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_ServiceItems" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_ServiceItems_CollectionThemes_CollectionThemeId" FOREIGN KEY ("CollectionThemeId") REFERENCES "CollectionThemes" ("Id") ON DELETE RESTRICT
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260418153720_InitialCreate') THEN
    CREATE TABLE "Employees" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "UserId" integer NOT NULL,
        "Specialty" character varying(100) NOT NULL,
        "QualificationLevel" integer NOT NULL,
        "About" character varying(600) NOT NULL,
        "HireDate" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_Employees" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Employees_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

